// Rotation quotidienne basée sur la date pour varier les sujets
const today = new Date();
const dayOffset = (today.getFullYear() * 365 + today.getMonth() * 30 + today.getDate()) % TARGETUP_TOPICS.length;

// Sélectionner 10 sujets par run (ajustez selon votre quota OpenRouter)
const BATCH_SIZE = 10;
const selected = [];
for (let i = 0; i < BATCH_SIZE; i++) {
  selected.push(TARGETUP_TOPICS[(dayOffset + i) % TARGETUP_TOPICS.length]);
}

return selected.map((t, idx) => ({
  json: {
    ...t,
    run_index: idx + 1,
    run_date: today.toISOString().split('T')[0],
    run_id: `TU-${today.toISOString().split('T')[0].replace(/-/g,'')}-${String(idx+1).padStart(3,'0')}`
  }
}));

const item = $input.item.json;

const PERSONAS = {
  DG:  "Directeur Général (DG/CEO) — focus ROI, transformation, performance globale, rentabilité",
  DSI: "Directeur des Systèmes d'Information (DSI) — focus digitalisation, ERP, intégration technique",
  QSE: "Responsable Qualité/HSE — focus certification, conformité ISO, amélioration continue",
  RH:  "Responsable Formation & RH — focus montée en compétences, certifications, ROI formation"
};

const BRAND = `Tu es le Chief Content Officer & SEO Strategist de TARGETUP GROUP (Maroc/Afrique).
TARGETUP CONSULTING : Conseil en excellence opérationnelle, Lean Six Sigma, ISO, ERP Odoo.
TARGETUP UNIVERSITY : Formations certifiantes PMP, Lean, ISO, Management.
Zone cible : Maroc et Afrique Francophone — PME, Grandes Entreprises, Secteur Public.
Vocabulaire obligatoire : DMAIC, GAP Analysis, CoPQ, VSM, Kaizen, Triple Bottom Line, ERP Workflow, CTQ, SPC, Cpk, EFQM, MSA.
Style : Institutionnel mais disruptif. Français impeccable. Orienté ROI. ZÉRO cliché IA.
CTA systématique : consulting@targetup.ma | https://www.targetup.ma/contact`;

const systemPrompt = `${BRAND}

PERSONA CIBLE : ${PERSONAS[item.persona] || PERSONAS.DG}

RÈGLES ABSOLUES :
- Français académique/professionnel impeccable
- Zéro cliché IA ("Dans le monde d'aujourd'hui", "En conclusion", "Il est important")
- Chaque phrase apporte valeur ou preuve d'expertise
- Chiffres, pourcentages et données mesurables systématiques
- Intégrer naturellement au moins 4 termes du vocabulaire obligatoire
- Longueur : 1200 à 1600 mots

STRUCTURE HTML OBLIGATOIRE :
<h1> Titre viral avec mot-clé (max 70 car.)
<div class="intro"> Introduction 3 phrases — briser un mythe ou poser un défi
<h2> x 4 minimum avec <h3> imbriqués
<ul>/<li> pour listes bénéfices/étapes
2 <blockquote> minimum — format "Conseil de l'Expert — Dr. Jendabi :"
1 <table> HTML structurant des données comparatives
<div class="cta"> à la fin — vers consulting@targetup.ma

RÉPONDRE UNIQUEMENT avec un objet JSON VALIDE (pas de markdown, pas de backticks) :
{
  "html": "...corps article HTML complet...",
  "seo": {
    "seo_title": "Titre SEO max 60 caractères",
    "meta_description": "Description SEO max 155 caractères",
    "slug": "url-sans-accents-ni-espaces-ni-caracteres-speciaux",
    "tags": ["Tag1", "Tag2", "Tag3", "Tag4", "Tag5"]
  }
}`;

const userPrompt = `SUJET : ${item.topic}
SERVICE TARGETUP : ${item.service}
PRIORITÉ SEO : ${item.priority}

Génère l'article d'autorité complet pour TARGETUP GROUP sur ce sujet.
Positionne TARGETUP comme leader incontesté de l'excellence opérationnelle en Afrique francophone.`;

return {
  json: {
    ...item,
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
};

const item = $input.item.json;

// Récupérer le texte brut généré par GPT-4o
let rawContent = '';
try {
  rawContent = item.choices[0].message.content;
} catch(e) {
  // Fallback si la structure est différente
  rawContent = JSON.stringify(item);
}

// Nettoyer les backticks markdown si présents
rawContent = rawContent
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

// Parser le JSON généré
let parsed = {};
try {
  parsed = JSON.parse(rawContent);
} catch(e) {
  // Si le JSON est invalide, créer un article de fallback
  const topicData = $('✍️ Construire Prompt TargetUp').item.json;
  parsed = {
    html: `<h1>${topicData.topic}</h1><div class="intro"><p>Article en cours de génération.</p></div>`,
    seo: {
      seo_title: topicData.topic.substring(0, 59),
      meta_description: `Article TARGETUP sur ${topicData.topic.substring(0, 100)}`,
      slug: topicData.topic.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').substring(0, 80),
      tags: ['TARGETUP', 'Excellence Opérationnelle', 'Maroc']
    }
  };
}

// Récupérer les données du sujet original
const topicData = $('✍️ Construire Prompt TargetUp').item.json;

// Générer le slug propre
function cleanSlug(text) {
  return text
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .substring(0, 80);
}

const slug = parsed.seo?.slug || cleanSlug(topicData.topic);

// Compter les mots approximativement
const wordCount = (parsed.html || '').replace(/<[^>]+>/g, ' ').split(/\s+/).filter(w => w.length > 0).length;

return {
  json: {
    // Données sujet
    topic: topicData.topic,
    persona: topicData.persona,
    service: topicData.service,
    run_id: topicData.run_id,
    run_date: topicData.run_date,
    // Article généré
    html_body: parsed.html || '',
    seo_title: (parsed.seo?.seo_title || topicData.topic).substring(0, 59),
    meta_description: (parsed.seo?.meta_description || '').substring(0, 154),
    slug: slug,
    tags: parsed.seo?.tags || ['TARGETUP', 'Excellence Opérationnelle'],
    word_count: wordCount,
    // Validation
    is_valid: (parsed.html || '').length > 300 && slug.length > 3,
    cost_usd: item.usage?.cost || 0,
    tokens_used: item.usage?.total_tokens || 0
  }
};

const article = $('🔍 Parser Réponse IA').item.json;
const authResult = $('🔐 Odoo Auth — Obtenir UID').item.json;
const blogResult = $('📖 Odoo — Récupérer Blog ID').item.json;

// Extraire l'UID Odoo
const uid = authResult.result;

// Extraire l'ID du blog (news-2 sur targetupconsulting.com)
let blogId = 2; // ID par défaut du blog News
if (blogResult.result && blogResult.result.length > 0) {
  blogId = blogResult.result[0].id;
}

// Préparer le contenu HTML final
const htmlContent = article.html_body;

// Construire les valeurs du blog.post
const blogPostValues = {
  name: article.seo_title || article.topic,
  blog_id: blogId,
  content: htmlContent,
  subtitle: `Guide Complet — ${article.service === 'Consulting' ? 'TARGETUP CONSULTING' : 'TARGETUP UNIVERSITY'}`,
  website_published: true,
  seo_name: article.slug,
  website_meta_title: article.seo_title,
  website_meta_description: article.meta_description,
  website_meta_keywords: article.tags.slice(0, 5).join(', '),
  author_id: 3
};

// Construire les valeurs du knowledge.article
const knowledgeValues = {
  name: article.seo_title || article.topic,
  body: htmlContent,
  icon: article.service === 'Consulting' ? '📊' : '🎓',
  internal_permission: 'read',
  is_article_visible_by_everyone: false
};

return {
  json: {
    uid: uid,
    blog_id: blogId,
    blog_post_values: JSON.stringify(blogPostValues),
    knowledge_values: JSON.stringify(knowledgeValues),
    // Passer les données article en avant
    article_topic: article.topic,
    article_slug: article.slug,
    article_seo_title: article.seo_title,
    article_word_count: article.word_count,
    article_tags: article.tags,
    run_id: article.run_id,
    run_date: article.run_date,
    cost_usd: article.cost_usd
  }
};

const prepData = $('🏗️ Préparer Données Odoo').item.json;
const blogResult = $('🌐 Publier Blog Odoo').item.json;
const knowledgeResult = $('📚 Publier Knowledge Odoo').item.json;

const blogPostId = blogResult.result || null;
const knowledgeId = knowledgeResult.result || null;

// Construire l'URL de l'article publié
const blogUrl = blogPostId 
  ? `https://targetupconsulting.com/en_GB/blog/news-2/${prepData.article_slug}-${blogPostId}`
  : null;

console.log(`✅ [${prepData.run_id}] Article publié:`);
console.log(`   Topic: ${prepData.article_topic}`);
console.log(`   Slug: ${prepData.article_slug}`);
console.log(`   Blog Post ID: ${blogPostId}`);
console.log(`   Knowledge ID: ${knowledgeId}`);
console.log(`   URL: ${blogUrl}`);
console.log(`   Mots: ${prepData.article_word_count}`);
console.log(`   Coût: $${prepData.cost_usd}`);

return {
  json: {
    status: 'SUCCESS',
    run_id: prepData.run_id,
    run_date: prepData.run_date,
    topic: prepData.article_topic,
    slug: prepData.article_slug,
    seo_title: prepData.article_seo_title,
    blog_post_id: blogPostId,
    knowledge_article_id: knowledgeId,
    published_url: blogUrl,
    word_count: prepData.article_word_count,
    tags: prepData.article_tags,
    cost_usd: prepData.cost_usd,
    published_at: new Date().toISOString()
  }
};

const item = $input.item.json;
console.error(`❌ Article invalide: ${item.topic}`);
console.error(`   Raison: html_length=${(item.html_body||'').length}, slug=${item.slug}`);

return {
  json: {
    status: 'INVALID',
    topic: item.topic,
    reason: `html_length: ${(item.html_body||'').length}, valid: ${item.is_valid}`,
    run_id: item.run_id,
    timestamp: new Date().toISOString()
  }
};

const items = $input.all();
const today = new Date().toISOString().split('T')[0];

console.log(`\n${'='.repeat(60)}`);
console.log(`TARGETUP CONTENT FACTORY — RAPPORT DU ${today}`);
console.log(`${'='.repeat(60)}`);
console.log(`Total items traités: ${items.length}`);
console.log(`${'='.repeat(60)}\n`);

return [{ json: { status: 'DONE', date: today, items_count: items.length } }];
